import { expect, it } from 'bun:test'
import { convert_pdf_to_webp } from '../../../utils/convert-pdf-to-webp'

it('should convert a PDF into a b64-webp', async () => {
  const pdfBytes = await Bun.file('./tests/unit/utils/__mocks__/input-2-pages.pdf').arrayBuffer()
  const file = new File([pdfBytes], 'input-2-pages.pdf', { type: 'application/pdf' })
  const form = new FormData()
  form.append('files', file)

  const files = form.getAll('files') as File[]

  expect(files).toHaveLength(1)
  expect(files[0].name).toBe('input-2-pages.pdf')

  const img = await convert_pdf_to_webp(files[0])

  expect(img).toMatchInlineSnapshot(
    `"data:image/webp;base64,"`
  )
})
